class Account {
    private static int nextId = 1;
    private final int accountId;
    private double balance;

    public Account(double balance) {
        if (balance < 0) throw new IllegalArgumentException("Balance cannot be negative");
        this.accountId = nextId++;
        this.balance = balance;
    }

    public void deposit(double amount) { balance += amount; }
    public double getBalance() { return balance; }
    public int getAccountId() { return accountId; }

    protected void setBalance(double balance) { this.balance = balance; }  // for subclasses
}

class SavingsAccount extends Account {
    private double interestRate;

    public SavingsAccount(double balance, double interestRate) {
        super(balance);
        this.interestRate = interestRate;
    }

    public void applyInterest() {
        double interest = getBalance() * (interestRate / 100);
        deposit(interest);
    }
}

public class App {
    public static void main(String[] args) {
        SavingsAccount sa = new SavingsAccount(5000, 5);
        sa.applyInterest();
        System.out.println("Account #" + sa.getAccountId() + " balance after interest: ₹" + sa.getBalance());
    }
}

class Product {
    private static int nextId = 1;
    private final int id;
    private String name;
    private double price;

    public Product(String name, double price) {
        this.id = nextId++;
        this.name = name;
        this.price = price;
    }

    public int getId() { return id; }
    public String getName() { return name; }
    public double getPrice() { return price; }

    @Override
    public String toString() {
        return "Product[#" + id + " " + name + " ₹" + price + "]";
    }
}

class DigitalProduct extends Product {
    private String fileSize;

    public DigitalProduct(String name, double price, String fileSize) {
        super(name, price);
        this.fileSize = fileSize;
    }

    @Override
    public String toString() {
        return super.toString() + " (download: " + fileSize + ")";
    }
}

class PhysicalProduct extends Product {
    private double weight;

    public PhysicalProduct(String name, double price, double weight) {
        super(name, price);
        this.weight = weight;
    }

    @Override
    public String toString() {
        return super.toString() + " (ships: " + weight + "kg)";
    }
}

public class App {
    public static void main(String[] args) {
        DigitalProduct dp = new DigitalProduct("Java Book", 599.0, "25MB");
        PhysicalProduct pp = new PhysicalProduct("Keyboard", 1999.0, 0.8);
        System.out.println(dp);
        System.out.println(pp);
    }
}

