class Vehicle {
    private int year;
    private String make;
    private String model;
    protected double fuelEfficiency;

    public Vehicle(String make, String model, int year, double fuelEfficiency) {
        this.year = year;
        this.make = make;
        this.model = model;
        this.fuelEfficiency = fuelEfficiency;
    }

    public int getYear() { return year; }
    public String getMake() { return make; }
    public String getModel() { return model; }

    @Override
    public String toString() {
        return make + " " + model + " (" + year + ")";
    }
}

class Car extends Vehicle {
    private int numDoors;

    public Car(String make, String model, int year, double fuelEfficiency, int numDoors) {
        super(make, model, year, fuelEfficiency);
        this.numDoors = numDoors;
    }

    @Override
    public String toString() {
        return super.toString() + ", " + numDoors + " doors";
    }
}

class ElectricCar extends Car {
    private int batteryRange;

    public ElectricCar(String make, String model, int year, int numDoors, int batteryRange) {
        super(make, model, year, 0, numDoors);  // no fuel efficiency
        this.batteryRange = batteryRange;
    }

    @Override
    public String toString() {
        return super.toString() + ", range: " + batteryRange + "km";
    }
}

public class App {
    public static void main(String[] args) {
        Vehicle v = new Vehicle("Toyota", "Camry", 2022, 14.5);
        Car c = new Car("Honda", "Civic", 2023, 15.0, 4);
        ElectricCar e = new ElectricCar("Tesla", "Model 3", 2024, 4, 500);

        System.out.println(v);
        System.out.println(c);
        System.out.println(e);
    }
}

class Employee {
    protected String name;
    protected double baseSalary;

    public Employee(String name, double baseSalary) {
        this.name = name;
        this.baseSalary = baseSalary;
    }

    public double calculateSalary() {
        return baseSalary;
    }

    public String getName() { return name; }
}

class Manager extends Employee {
    private double bonus;

    public Manager(String name, double baseSalary, double bonus) {
        super(name, baseSalary);
        this.bonus = bonus;
    }

    @Override
    public double calculateSalary() {
        return baseSalary + bonus;
    }
}

class SalesEmployee extends Employee {
    private double commissionRate;
    private double salesAmount;

    public SalesEmployee(String name, double baseSalary, double commissionRate, double salesAmount) {
        super(name, baseSalary);
        this.commissionRate = commissionRate;
        this.salesAmount = salesAmount;
    }

    @Override
    public double calculateSalary() {
        return baseSalary + salesAmount * commissionRate;
    }
}

public class App {
    public static void main(String[] args) {
        Employee[] staff = {
            new Employee("Aisha", 75000),
            new Manager("Raj", 85000, 15000),
            new SalesEmployee("Priya", 60000, 0.05, 570000)
        };

        for (Employee e : staff) {
            System.out.println(e.getName() + ": ₹" + e.calculateSalary());
        }
    }
}

class Notification {
    private String message;
    private int priority;

    public Notification(String message, int priority) {
        if (message == null || message.isBlank()) throw new IllegalArgumentException("Message required");
        if (priority < 1 || priority > 5) throw new IllegalArgumentException("Priority must be 1-5");
        this.message = message;
        this.priority = priority;
    }

    public String getMessage() { return message; }
    public int getPriority() { return priority; }

    public void send() {
        System.out.println("[PRIORITY-" + priority + "] " + message);
    }

    public String getLog() {
        return "Notification: " + message;
    }
}

class EmailNotification extends Notification {
    private String recipientEmail;

    public EmailNotification(String message, int priority, String recipientEmail) {
        super(message, priority);
        this.recipientEmail = recipientEmail;
    }

    @Override
    public void send() {
        super.send();
        System.out.println("Sent to: " + recipientEmail);
    }

    @Override
    public String getLog() {
        return "Email | " + super.getLog();
    }
}

class SMSNotification extends Notification {
    private String phoneNumber;

    public SMSNotification(String message, int priority, String phoneNumber) {
        super(message, priority);
        this.phoneNumber = phoneNumber;
    }

    @Override
    public void send() {
        super.send();
        System.out.println("Sent to: " + phoneNumber);
    }

    @Override
    public String getLog() {
        return "SMS | " + super.getLog();
    }
}

public class App {
    public static void main(String[] args) {
        EmailNotification email = new EmailNotification("Server is down!", 1, "ops@company.com");
        SMSNotification sms = new SMSNotification("Reminder: meeting at 3pm", 3, "+919876543210");

        email.send();
        System.out.println("Log: " + email.getLog());

        sms.send();
        System.out.println("Log: " + sms.getLog());
    }
}
